import React, { useState } from 'react';
import { GraduationCap, Plus, Edit, Trash2, Users, Star, DollarSign, BookOpen, TrendingUp, BarChart3, PieChart, Video, Eye, X } from 'lucide-react';
import { RevenueChart, EnrollmentChart, PerformanceChart } from './components/Charts.jsx';
import VideoPlayer from './components/VideoPlayer.jsx';
import CourseModal from './components/CourseModal.jsx';
import CourseUploadModal from './components/CourseUploadModal.jsx';
// import EditModal from './components/EditModal.jsx';

const InstructorPage = ({ courses, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showCourseModal, setShowCourseModal] = useState(false);
  const [showVideoModal, setShowVideoModal] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [selectedVideo, setSelectedVideo] = useState(null);
  const [dragActive, setDragActive] = useState(false);
  const [thumbnailDragActive, setThumbnailDragActive] = useState(false);
  const [courseForm, setCourseForm] = useState({
    title: '',
    desc: '',
    price: '',
    cat: 'development',
    level: 'Beginner',
    time: '',
    instructor: 'Current User',
    img: 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?w=400&h=200&fit=crop',
    videos: [],
    videoType: 'link',
    newVideoUrl: ''
  });

  const instructorStats = {
    totalCourses: courses.length,
    totalStudents: courses.reduce((sum, course) => sum + course.enrolled, 0),
    totalRevenue: courses.reduce((sum, course) => sum + (course.price * course.enrolled), 0),
    avgRating: courses.length > 0 ? (courses.reduce((sum, course) => sum + parseFloat(course.rating), 0) / courses.length).toFixed(1) : '0.0'
  };

  const resetForm = () => {
    setCourseForm({
      title: '',
      desc: '',
      price: '',
      cat: 'development',
      level: 'Beginner',
      time: '',
      instructor: 'Current User',
      img: 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?w=400&h=200&fit=crop',
      videos: [],
      videoType: 'link',
      newVideoUrl: ''
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (courseForm.title && courseForm.desc && courseForm.price) {
      onAddCourse({
        ...courseForm,
        price: parseInt(courseForm.price),
        videoUrl: courseForm.videos.length > 0 ? courseForm.videos[0] : ''
      });
      resetForm();
      setShowUploadModal(false);
    }
  };

  const handleEditSubmit = (e) => {
    e.preventDefault();
    if (courseForm.title && courseForm.desc && courseForm.price && selectedCourse) {
      onUpdateCourse(selectedCourse.id, {
        ...courseForm,
        price: parseInt(courseForm.price),
        videoUrl: courseForm.videos.length > 0 ? courseForm.videos[0] : '',
        videos: courseForm.videos
      });
      setShowEditModal(false);
      setSelectedCourse(null);
    }
  };

  const handleDelete = (courseId, courseTitle) => {
    if (window.confirm(`Are you sure you want to delete "${courseTitle}"?`)) {
      onDeleteCourse(courseId);
    }
  };

  const editCourse = (course) => {
    setSelectedCourse(course);
    const existingVideos = [];
    if (course.videoUrl) existingVideos.push(course.videoUrl);
    if (course.videos && Array.isArray(course.videos)) {
      course.videos.forEach(video => {
        if (video && !existingVideos.includes(video)) {
          existingVideos.push(video);
        }
      });
    }
    setCourseForm({
      title: course.title,
      desc: course.desc,
      price: course.price.toString(),
      cat: course.cat,
      level: course.level,
      time: course.time,
      instructor: course.instructor,
      img: course.img,
      videos: existingVideos,
      videoType: 'link',
      newVideoUrl: ''
    });
    setShowEditModal(true);
  };

  const closeEditModal = () => {
    console.log('Close button clicked');
    setShowEditModal(false);
    setSelectedCourse(null);
    resetForm();
  };

  const viewCourse = (course) => {
    setSelectedCourse(course);
    setShowCourseModal(true);
  };

  const handleVideoUpload = (file) => {
    if (file?.type.startsWith('video/')) {
      setCourseForm({...courseForm, videos: [...courseForm.videos, URL.createObjectURL(file)]});
    }
  };

  const handleThumbnailUpload = (file) => {
    if (file?.type.startsWith('image/')) {
      setCourseForm({...courseForm, img: URL.createObjectURL(file)});
    }
  };

  const removeVideo = (index) => {
    setCourseForm({...courseForm, videos: courseForm.videos.filter((_, i) => i !== index)});
  };

  const addVideoUrl = () => {
    if (courseForm.newVideoUrl.trim()) {
      setCourseForm({
        ...courseForm,
        videos: [...courseForm.videos, courseForm.newVideoUrl.trim()],
        newVideoUrl: ''
      });
    }
  };

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(e.type === "dragenter" || e.type === "dragover");
  };

  const handleThumbnailDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setThumbnailDragActive(e.type === "dragenter" || e.type === "dragover");
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files?.[0]) handleVideoUpload(e.dataTransfer.files[0]);
  };

  const handleThumbnailDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setThumbnailDragActive(false);
    if (e.dataTransfer.files?.[0]) handleThumbnailUpload(e.dataTransfer.files[0]);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-50">
      <header className="bg-white/80 backdrop-blur-md shadow-lg border-b border-white/20">
        <div className="max-w-7xl mx-auto px-4 py-6">
          <div className="flex justify-between items-center">
            <div className="flex items-center">
              <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-2 rounded-xl mr-4">
                <GraduationCap className="w-8 h-8 text-white" />
              </div>
              <div>
                <h1 className="text-3xl font-bold bg-gradient-to-r from-gray-900 to-gray-700 bg-clip-text text-transparent">Instructor Dashboard</h1>
                <p className="text-sm text-gray-600 mt-1">Manage your courses and track performance</p>
              </div>
            </div>
            <button 
              onClick={() => setShowUploadModal(true)}
              className="bg-gradient-to-r from-blue-600 to-indigo-600 text-white px-6 py-3 rounded-xl flex items-center hover:from-blue-700 hover:to-indigo-700 transition-all duration-300 shadow-lg hover:shadow-xl transform hover:-translate-y-0.5"
            >
              <Plus className="w-5 h-5 mr-2" />
              New Course
            </button>
          </div>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 py-8">
        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
          <div className="bg-white/70 backdrop-blur-sm p-6 rounded-2xl shadow-xl border border-white/20 hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1 relative overflow-hidden">
            <div className="absolute inset-0 bg-gradient-to-br from-blue-500/10 to-blue-600/5"></div>
            <div className="relative flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600 mb-2 font-medium">Total Courses</p>
                <p className="text-4xl font-bold bg-gradient-to-r from-blue-600 to-blue-700 bg-clip-text text-transparent">{instructorStats.totalCourses}</p>
                <p className="text-xs text-emerald-600 mt-2 flex items-center">
                  <TrendingUp className="w-3 h-3 mr-1" />+2 this month
                </p>
              </div>
              <div className="bg-gradient-to-br from-blue-500 to-blue-600 p-4 rounded-2xl shadow-lg">
                <BookOpen className="w-8 h-8 text-white" />
              </div>
            </div>
          </div>

          <div className="bg-white/70 backdrop-blur-sm p-6 rounded-2xl shadow-xl border border-white/20 hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1 relative overflow-hidden">
            <div className="absolute inset-0 bg-gradient-to-br from-emerald-500/10 to-emerald-600/5"></div>
            <div className="relative flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600 mb-2 font-medium">Total Students</p>
                <p className="text-4xl font-bold bg-gradient-to-r from-emerald-600 to-emerald-700 bg-clip-text text-transparent">{instructorStats.totalStudents.toLocaleString()}</p>
                <p className="text-xs text-emerald-600 mt-2 flex items-center">
                  <TrendingUp className="w-3 h-3 mr-1" />+12% growth
                </p>
              </div>
              <div className="bg-gradient-to-br from-emerald-500 to-emerald-600 p-4 rounded-2xl shadow-lg">
                <Users className="w-8 h-8 text-white" />
              </div>
            </div>
          </div>

          <div className="bg-white/70 backdrop-blur-sm p-6 rounded-2xl shadow-xl border border-white/20 hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1 relative overflow-hidden">
            <div className="absolute inset-0 bg-gradient-to-br from-amber-500/10 to-amber-600/5"></div>
            <div className="relative flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600 mb-2 font-medium">Total Revenue</p>
                <p className="text-4xl font-bold bg-gradient-to-r from-amber-600 to-amber-700 bg-clip-text text-transparent">₹{instructorStats.totalRevenue.toLocaleString()}</p>
                <p className="text-xs text-emerald-600 mt-2 flex items-center">
                  <TrendingUp className="w-3 h-3 mr-1" />+8% this month
                </p>
              </div>
              <div className="bg-gradient-to-br from-amber-500 to-amber-600 p-4 rounded-2xl shadow-lg">
                <DollarSign className="w-8 h-8 text-white" />
              </div>
            </div>
          </div>

          <div className="bg-white/70 backdrop-blur-sm p-6 rounded-2xl shadow-xl border border-white/20 hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1 relative overflow-hidden">
            <div className="absolute inset-0 bg-gradient-to-br from-purple-500/10 to-purple-600/5"></div>
            <div className="relative flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600 mb-2 font-medium">Avg Rating</p>
                <p className="text-4xl font-bold bg-gradient-to-r from-purple-600 to-purple-700 bg-clip-text text-transparent">{instructorStats.avgRating}</p>
                <p className="text-xs text-emerald-600 mt-2 flex items-center">
                  <Star className="w-3 h-3 mr-1 fill-current" />Excellent!
                </p>
              </div>
              <div className="bg-gradient-to-br from-purple-500 to-purple-600 p-4 rounded-2xl shadow-lg">
                <Star className="w-8 h-8 text-white" />
              </div>
            </div>
          </div>
        </div>

        {/* Charts Section */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
          <div className="bg-white/70 backdrop-blur-sm p-6 rounded-2xl shadow-xl border border-white/20 hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1">
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-bold text-gray-800">Revenue Trend</h3>
              <div className="flex items-center bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full">
                <TrendingUp className="w-4 h-4 mr-1" />
                <span className="text-sm font-semibold">+15%</span>
              </div>
            </div>
            <RevenueChart />
            <p className="text-sm text-gray-600 mt-4 text-center font-medium">Last 7 days performance</p>
          </div>

          <div className="bg-white/70 backdrop-blur-sm p-6 rounded-2xl shadow-xl border border-white/20 hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1">
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-bold text-gray-800">Weekly Enrollments</h3>
              <div className="flex items-center bg-blue-50 text-blue-600 px-3 py-1 rounded-full">
                <BarChart3 className="w-4 h-4 mr-1" />
                <span className="text-sm font-semibold">+8%</span>
              </div>
            </div>
            <EnrollmentChart />
            <p className="text-sm text-gray-600 mt-4 text-center font-medium">Weekly enrollment trends</p>
          </div>

          <div className="bg-white/70 backdrop-blur-sm p-6 rounded-2xl shadow-xl border border-white/20 hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1">
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-bold text-gray-800">Course Performance</h3>
              <div className="bg-purple-50 text-purple-600 p-2 rounded-full">
                <PieChart className="w-4 h-4" />
              </div>
            </div>
            <PerformanceChart />
            <p className="text-sm text-gray-600 mt-4 text-center font-medium">Category-wise performance</p>
          </div>
        </div>

        {/* Tabs Section */}
        <div className="bg-white/70 backdrop-blur-sm rounded-2xl shadow-xl border border-white/20 overflow-hidden">
          <div className="border-b border-gray-200/50 bg-gradient-to-r from-gray-50/50 to-white/50">
            <nav className="flex space-x-8 px-6">
              {[
                { key: 'dashboard', label: 'Dashboard', icon: BarChart3 },
                { key: 'courses', label: 'My Courses', icon: BookOpen },
                { key: 'analytics', label: 'Analytics', icon: TrendingUp }
              ].map(tab => (
                <button
                  key={tab.key}
                  onClick={() => setActiveTab(tab.key)}
                  className={`py-4 px-2 border-b-3 font-semibold text-sm flex items-center transition-all duration-300 ${
                    activeTab === tab.key 
                      ? 'border-blue-500 text-blue-600 bg-blue-50/50 rounded-t-lg' 
                      : 'border-transparent text-gray-500 hover:text-gray-700 hover:bg-gray-50/30 rounded-t-lg'
                  }`}
                >
                  <tab.icon className="w-5 h-5 mr-2" />
                  {tab.label}
                </button>
              ))}
            </nav>
          </div>

          <div className="p-8">
            {activeTab === 'courses' && (
              <div>
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-xl font-semibold text-gray-800">My Courses ({courses.length})</h3>
                  <div className="text-sm text-gray-600">
                    Total Revenue: ₹{instructorStats.totalRevenue.toLocaleString()}
                  </div>
                </div>
                <div className="space-y-6">
                  {courses.map(course => (
                    <div key={course.id} className="bg-white/50 backdrop-blur-sm border border-white/30 rounded-2xl p-6 hover:bg-white/70 hover:shadow-lg transition-all duration-300 transform hover:-translate-y-1">
                      <div className="flex justify-between items-center">
                        <div className="flex items-center space-x-6">
                          <div className="relative">
                            <img src={course.img} alt={course.title} className="w-20 h-20 rounded-2xl object-cover shadow-lg" />
                            <div className="absolute -top-2 -right-2 bg-gradient-to-r from-emerald-500 to-emerald-600 text-white text-xs px-2 py-1 rounded-full font-semibold">
                              Live
                            </div>
                          </div>
                          <div>
                            <h4 className="font-bold text-gray-900 text-lg mb-2">{course.title}</h4>
                            <div className="flex items-center space-x-6 text-sm text-gray-600 mb-3">
                              <span className="flex items-center bg-blue-50 px-3 py-1 rounded-full">
                                <Users className="w-4 h-4 mr-2 text-blue-600" />
                                <span className="font-semibold">{course.enrolled}</span> students
                              </span>
                              <span className="flex items-center bg-amber-50 px-3 py-1 rounded-full">
                                <Star className="w-4 h-4 mr-2 text-amber-500 fill-current" />
                                <span className="font-semibold">{course.rating}</span>
                              </span>
                              <span className="flex items-center bg-emerald-50 px-3 py-1 rounded-full font-semibold text-emerald-700">
                                <DollarSign className="w-4 h-4 mr-1" />
                                ₹{course.price}
                              </span>
                              <span className="bg-gradient-to-r from-green-500 to-emerald-500 text-white px-3 py-1 rounded-full font-bold text-sm">
                                ₹{(course.price * course.enrolled).toLocaleString()}
                              </span>
                              {((course.videos && course.videos.length > 0) || course.videoUrl) && (
                                <span className="flex items-center bg-purple-50 px-3 py-1 rounded-full text-purple-700">
                                  <Video className="w-4 h-4 mr-2" />
                                  <span className="font-semibold">{course.videos ? `${course.videos.length} Videos` : 'Video'}</span>
                                </span>
                              )}
                            </div>
                            <div className="flex items-center space-x-3">
                              <span className="px-3 py-1 rounded-full text-xs bg-gradient-to-r from-emerald-500 to-emerald-600 text-white font-semibold">
                                Published
                              </span>
                              <span className="text-sm text-gray-600 bg-gray-100 px-3 py-1 rounded-full">
                                {course.cat.charAt(0).toUpperCase() + course.cat.slice(1)}
                              </span>
                            </div>
                          </div>
                        </div>
                        <div className="flex space-x-3">
                          <button 
                            onClick={() => viewCourse(course)}
                            className="p-3 text-gray-600 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all duration-300 transform hover:scale-110 shadow-md hover:shadow-lg"
                          >
                            <Eye className="w-5 h-5" />
                          </button>
                          <button 
                            onClick={() => editCourse(course)}
                            className="p-3 text-gray-600 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all duration-300 transform hover:scale-110 shadow-md hover:shadow-lg"
                          >
                            <Edit className="w-5 h-5" />
                          </button>
                          <button 
                            onClick={() => handleDelete(course.id, course.title)}
                            className="p-3 text-gray-600 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all duration-300 transform hover:scale-110 shadow-md hover:shadow-lg"
                          >
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'dashboard' && (
              <div>
                <h3 className="text-xl font-semibold text-gray-800 mb-6">Recent Activity</h3>
                <div className="space-y-4">
                  {[
                    { type: 'success', message: 'Course edited and video updated successfully', time: '1 hour ago' },
                    { type: 'info', message: 'Course received new enrollment', time: '4 hours ago' },
                    { type: 'warning', message: 'Payment of ₹15,000 received', time: '1 day ago' },
                    { type: 'info', message: 'Course rating updated to 4.8', time: '2 days ago' }
                  ].map((activity, index) => (
                    <div key={index} className="flex items-center p-5 bg-white/50 backdrop-blur-sm rounded-2xl hover:bg-white/70 hover:shadow-lg transition-all duration-300 transform hover:-translate-y-1 border border-white/30">
                      <div className={`w-4 h-4 rounded-full mr-5 shadow-lg ${
                        activity.type === 'success' ? 'bg-gradient-to-r from-emerald-500 to-emerald-600' :
                        activity.type === 'info' ? 'bg-gradient-to-r from-blue-500 to-blue-600' :
                        activity.type === 'warning' ? 'bg-gradient-to-r from-amber-500 to-amber-600' : 'bg-gradient-to-r from-gray-500 to-gray-600'
                      }`} />
                      <div className="flex-1">
                        <span className="text-sm font-semibold text-gray-900">{activity.message}</span>
                        <p className="text-xs text-gray-600 mt-1 font-medium">{activity.time}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'analytics' && (
              <div>
                <h3 className="text-xl font-semibold text-gray-800 mb-6">Detailed Analytics</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  <div className="bg-gradient-to-br from-emerald-50 via-emerald-100 to-emerald-200 p-8 rounded-2xl border border-emerald-200/50 shadow-xl hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1">
                    <h4 className="font-bold text-emerald-800 mb-3 text-lg">Monthly Revenue</h4>
                    <div className="text-4xl font-bold bg-gradient-to-r from-emerald-700 to-emerald-800 bg-clip-text text-transparent mb-2">₹{Math.floor(instructorStats.totalRevenue * 0.3).toLocaleString()}</div>
                    <p className="text-sm text-emerald-700 font-semibold flex items-center">
                      <TrendingUp className="w-4 h-4 mr-1" />+12% from last month
                    </p>
                  </div>
                  <div className="bg-gradient-to-br from-blue-50 via-blue-100 to-blue-200 p-8 rounded-2xl border border-blue-200/50 shadow-xl hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1">
                    <h4 className="font-bold text-blue-800 mb-3 text-lg">New Enrollments</h4>
                    <div className="text-4xl font-bold bg-gradient-to-r from-blue-700 to-blue-800 bg-clip-text text-transparent mb-2">{Math.floor(instructorStats.totalStudents * 0.1)}</div>
                    <p className="text-sm text-blue-700 font-semibold flex items-center">
                      <TrendingUp className="w-4 h-4 mr-1" />+8% from last month
                    </p>
                  </div>
                  <div className="bg-gradient-to-br from-purple-50 via-purple-100 to-purple-200 p-8 rounded-2xl border border-purple-200/50 shadow-xl hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1">
                    <h4 className="font-bold text-purple-800 mb-3 text-lg">Course Completion</h4>
                    <div className="text-4xl font-bold bg-gradient-to-r from-purple-700 to-purple-800 bg-clip-text text-transparent mb-2">78%</div>
                    <p className="text-sm text-purple-700 font-semibold flex items-center">
                      <TrendingUp className="w-4 h-4 mr-1" />+5% improvement
                    </p>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      <CourseUploadModal 
        show={showUploadModal}
        onClose={() => setShowUploadModal(false)}
        courseForm={courseForm}
        setCourseForm={setCourseForm}
        onSubmit={handleSubmit}
        dragActive={dragActive}
        thumbnailDragActive={thumbnailDragActive}
        handleDrag={handleDrag}
        handleThumbnailDrag={handleThumbnailDrag}
        handleDrop={handleDrop}
        handleThumbnailDrop={handleThumbnailDrop}
        handleVideoUpload={handleVideoUpload}
        handleThumbnailUpload={handleThumbnailUpload}
        removeVideo={removeVideo}
        addVideoUrl={addVideoUrl}
      />

      {showEditModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl max-w-md w-full shadow-2xl">
            <div className="p-6 border-b flex justify-between items-center">
              <h2 className="text-xl font-bold text-gray-900">Edit Course</h2>
              <button 
                onClick={() => {
                  alert('X clicked!');
                  closeEditModal();
                }}
                className="bg-red-500 text-white p-3 rounded-full hover:bg-red-600"
              >
                <X className="w-5 h-5" />
              </button>
            </div>
            <div className="p-6">
              <form onSubmit={handleEditSubmit} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Course Title</label>
                  <input 
                    type="text" 
                    value={courseForm.title}
                    onChange={(e) => setCourseForm({...courseForm, title: e.target.value})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2" 
                    required
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Price (₹)</label>
                  <input 
                    type="number" 
                    value={courseForm.price}
                    onChange={(e) => setCourseForm({...courseForm, price: e.target.value})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2" 
                    required
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Description</label>
                  <textarea 
                    value={courseForm.desc}
                    onChange={(e) => setCourseForm({...courseForm, desc: e.target.value})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 h-20" 
                    required
                  />
                </div>
                <div className="flex gap-3 pt-4">
                  <button type="submit" className="flex-1 bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700">
                    Update Course
                  </button>
                  <button 
                    type="button"
                    onClick={closeEditModal}
                    className="px-6 bg-gray-200 text-gray-700 py-2 rounded-lg hover:bg-gray-300"
                  >
                    Cancel
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      <CourseModal 
        course={selectedCourse}
        onClose={() => setShowCourseModal(false)}
        onVideoPlay={(video) => {
          setSelectedVideo(video);
          setShowVideoModal(true);
        }}
        onDelete={handleDelete}
      />

      <VideoPlayer 
        selectedVideo={selectedVideo}
        onClose={() => {
          setShowVideoModal(false);
          setSelectedVideo(null);
        }}
      />
    </div>
  );
};

export default InstructorPage;
